class Solution:
    def maxValue(self, nums):
        n = len(nums)
        parent = list(range(n))
        def f(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        for i in range(n):
            for j in range(i + 1, n):
                if nums[i] > nums[j]:
                    parent[f(i)] = f(j)
        from collections import defaultdict
        mx = defaultdict(int)
        for i in range(n):
            r = f(i)
            if nums[i] > mx[r]:
                mx[r] = nums[i]
        return [mx[f(i)] for i in range(n)]

