class Solution:
    def maxValue(self, nums):
        n = len(nums)
        if n == 0:
            return []
        sufmin = [0] * n
        sufmin[-1] = nums[-1]
        for i in range(n - 2, -1, -1):
            sufmin[i] = min(nums[i], sufmin[i + 1])
        out = [0] * n
        i = 0
        while i < n:
            j = i
            cur_max = nums[i]
            while j < n - 1 and cur_max > sufmin[j + 1]:
                j += 1
                if nums[j] > cur_max:
                    cur_max = nums[j]
            for k in range(i, j + 1):
                out[k] = cur_max
            i = j + 1
        return out

