var maxValue = function(nums) {
    const n = nums.length;
    if (n === 0) return [];
    const sufmin = new Array(n);
    sufmin[n - 1] = nums[n - 1];
    for (let i = n - 2; i >= 0; i--) sufmin[i] = Math.min(nums[i], sufmin[i + 1]);
    const out = new Array(n);
    let i = 0;
    while (i < n) {
        let j = i, curMax = nums[i];
        while (j < n - 1 && curMax > sufmin[j + 1]) {
            j++;
            if (nums[j] > curMax) curMax = nums[j];
        }
        for (let k = i; k <= j; k++) out[k] = curMax;
        i = j + 1;
    }
    return out;
};
